firestore.rules:
rules_version = '2';
service cloud.firestore {
  match /databases/{database}/documents {

    // ── USERS ──────────────────────────────────────────────────────────────
    match /users/{userId} {
      // Authenticated user can read/write their own document
      allow read, update: if request.auth != null && request.auth.uid == userId;
      // Anyone can create a user doc on signup
      allow create: if request.auth != null;
      // Only admin emails can delete accounts
      allow delete: if request.auth != null &&
        (request.auth.token.email == 'bishwaprakashrout2007@gmail.com' ||
         request.auth.token.email == 'asitraut2006@gmail.com');
    }

    // ── NGOs ───────────────────────────────────────────────────────────────
    match /ngos/{ngoId} {
      // Anyone authenticated can read verified NGO profiles
      allow read: if request.auth != null;
      // NGO owner can create/update their own profile
      allow create, update: if request.auth != null && request.auth.uid == ngoId;
      // Only admins can delete NGO entries
      allow delete: if request.auth != null &&
        (request.auth.token.email == 'bishwaprakashrout2007@gmail.com' ||
         request.auth.token.email == 'asitraut2006@gmail.com');
    }

    // ── DONATIONS ──────────────────────────────────────────────────────────
    match /donations/{donationId} {
      // Donor or assigned NGO can read their donation
      allow read: if request.auth != null &&
        (resource.data.donorId == request.auth.uid ||
         resource.data.ngoId == request.auth.uid ||
         request.auth.token.email == 'bishwaprakashrout2007@gmail.com' ||
         request.auth.token.email == 'asitraut2006@gmail.com');
      // Authenticated clients can create donation requests
      allow create: if request.auth != null;
      // Donor or NGO can update status fields; admins can update anything
      allow update: if request.auth != null &&
        (resource.data.donorId == request.auth.uid ||
         resource.data.ngoId == request.auth.uid ||
         request.auth.token.email == 'bishwaprakashrout2007@gmail.com' ||
         request.auth.token.email == 'asitraut2006@gmail.com');
      allow delete: if request.auth != null &&
        (request.auth.token.email == 'bishwaprakashrout2007@gmail.com' ||
         request.auth.token.email == 'asitraut2006@gmail.com');
    }

    // ── BLOGS ──────────────────────────────────────────────────────────────
    match /blogs/{blogId} {
      allow read: if true; // Public
      allow write: if request.auth != null &&
        (request.auth.token.email == 'bishwaprakashrout2007@gmail.com' ||
         request.auth.token.email == 'asitraut2006@gmail.com');
    }

    // ── GALLERY ────────────────────────────────────────────────────────────
    match /gallery/{imageId} {
      allow read: if true; // Public
      allow create: if request.auth != null;
      allow delete: if request.auth != null &&
        (request.auth.token.email == 'bishwaprakashrout2007@gmail.com' ||
         request.auth.token.email == 'asitraut2006@gmail.com');
    }

    // ── FEEDBACK ───────────────────────────────────────────────────────────
    match /feedback/{feedbackId} {
      allow read: if true; // Public testimonials
      allow create: if true; // Anyone can submit feedback
      allow delete: if request.auth != null &&
        (request.auth.token.email == 'bishwaprakashrout2007@gmail.com' ||
         request.auth.token.email == 'asitraut2006@gmail.com');
    }

    // ── VERIFICATIONS ──────────────────────────────────────────────────────
    match /verifications/{verificationId} {
      allow read: if request.auth != null &&
        (resource.data.ngoId == request.auth.uid ||
         request.auth.token.email == 'bishwaprakashrout2007@gmail.com' ||
         request.auth.token.email == 'asitraut2006@gmail.com');
      allow create: if request.auth != null;
      allow update: if request.auth != null &&
        (request.auth.token.email == 'bishwaprakashrout2007@gmail.com' ||
         request.auth.token.email == 'asitraut2006@gmail.com');
    }

    // ── NOTIFICATIONS ──────────────────────────────────────────────────────
    match /notifications/{notificationId} {
      allow read: if request.auth != null &&
        resource.data.userId == request.auth.uid;
      allow create: if request.auth != null;
      allow update, delete: if request.auth != null &&
        resource.data.userId == request.auth.uid;
    }

    // Deny everything else
    match /{document=**} {
      allow read, write: if false;
    }
  }
}

storage.rules:
rules_version = '2';
service firebase.storage {
  match /b/{bucket}/o {

    // NGO profile photos and KYC docs
    match /ngos/{ngoId}/{allPaths=**} {
      allow read: if request.auth != null;
      allow write: if request.auth != null && request.auth.uid == ngoId
        && request.resource.size < 5 * 1024 * 1024  // 5 MB max
        && (request.resource.contentType.matches('image/.*') ||
            request.resource.contentType == 'application/pdf');
    }

    // Donation receipt photos
    match /donation_receipts/{donationId}/{allPaths=**} {
      allow read: if request.auth != null;
      allow write: if request.auth != null
        && request.resource.size < 5 * 1024 * 1024
        && request.resource.contentType.matches('image/.*');
    }

    // KYC verification documents
    match /kyc_documents/{userId}/{allPaths=**} {
      allow read: if request.auth != null &&
        (request.auth.uid == userId ||
         request.auth.token.email == 'bishwaprakashrout2007@gmail.com' ||
         request.auth.token.email == 'asitraut2006@gmail.com');
      allow write: if request.auth != null && request.auth.uid == userId
        && request.resource.size < 10 * 1024 * 1024  // 10 MB
        && (request.resource.contentType.matches('image/.*') ||
            request.resource.contentType == 'application/pdf');
    }

    // Public gallery images
    match /public_uploads/{allPaths=**} {
      allow read: if true;
      allow write: if request.auth != null
        && request.resource.size < 5 * 1024 * 1024
        && request.resource.contentType.matches('image/.*');
    }

    // Deny all other paths
    match /{allPaths=**} {
      allow read, write: if false;
    }
  }
}
